// Maquina de estados del RACS
// estados: NUEVO, ESPERANDO_FOTO, ESPERANDO_GPS, ESPERANDO_DESCRIPCION, CLASIFICANDO
const sesion = $input.first().json;
const entrada = $('Router · tipo de mensaje').first().json;
let siguienteEstado;
let respuestaBot;
let payload = sesion.payload || {};

if (!sesion.estado || entrada.body.text === 'RACS') {
  siguienteEstado = 'ESPERANDO_FOTO';
  respuestaBot = 'Hola 👷 Vamos a registrar el RACS. Mándame primero una foto.';
  payload = { iniciado: new Date().toISOString() };
} else if (sesion.estado === 'ESPERANDO_FOTO' && entrada.outputKey === 'foto') {
  siguienteEstado = 'ESPERANDO_GPS';
  respuestaBot = '✓ Foto recibida. Ahora envíame tu ubicación en vivo 📍';
  payload.foto_url = entrada.body.message.imageMessage.url;
} else if (sesion.estado === 'ESPERANDO_GPS' && entrada.outputKey === 'ubicacion') {
  siguienteEstado = 'ESPERANDO_DESCRIPCION';
  respuestaBot = 'Cuéntame qué viste 🎤 (texto o nota de voz)';
  payload.gps = { lat: entrada.body.message.locationMessage.degreesLatitude, lon: entrada.body.message.locationMessage.degreesLongitude };
} else if (sesion.estado === 'ESPERANDO_DESCRIPCION' && (entrada.outputKey === 'texto' || entrada.outputKey === 'voz')) {
  siguienteEstado = 'CLASIFICANDO';
  respuestaBot = '⚡ Procesando con Gemini Pro...';
  payload.descripcion_raw = entrada.outputKey === 'voz' ? entrada.body.message.audioMessage.url : entrada.body.text;
  payload.tipo_descripcion = entrada.outputKey;
} else {
  siguienteEstado = sesion.estado;
  respuestaBot = 'Disculpa, no entendí. ¿Estás en medio de un RACS? Escribe RACS para empezar de cero.';
}
return [{ json: { estado: siguienteEstado, payload, respuestaBot, telefono: entrada.body.from } }];

